```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = 1702;

const DATA_FILE = path.join(__dirname, 'data', 'state.json');
const INDEX_FILE = path.join(__dirname, 'index.html');

// Middleware
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public'))); // serve public assets if any

// Load state
function loadState() {
    try {
        if (fs.existsSync(DATA_FILE)) {
            const raw = fs.readFileSync(DATA_FILE, 'utf8');
            return JSON.parse(raw);
        }
    } catch (e) {
        console.error('Error loading state, returning default:', e.message);
    }
    return {};
}

// Save state
function saveState(state) {
    try {
        const dir = path.dirname(DATA_FILE);
        if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
        fs.writeFileSync(DATA_FILE, JSON.stringify(state, null, 2));
    } catch (e) {
        console.error('Error saving state:', e.message);
    }
}

// Serve index.html
app.get('/', (req, res) => {
    res.sendFile(INDEX_FILE);
});

// GET state
app.get('/api/state', (req, res) => {
    const state = loadState();
    res.json(state);
});

// POST state (merge)
app.post('/api/state', (req, res) => {
    const current = loadState();
    const update = req.body;
    // Deep merge (simple merge for top-level keys)
    Object.keys(update).forEach(key => {
        current[key] = update[key];
    });
    saveState(current);
    res.json(current);
});

app.listen(PORT, '0.0.0.0', () => {
    console.log(`Productivity Dashboard running on http://0.0.0.0:${PORT}`);
});
```

Current backend is minimal – just serves the HTML and a JSON state API. No sidebar logic server-side. The redesign will happen in `index.html` (JS + CSS). Server probably doesn't need changes unless we add dynamic sidebar data endpoints.

